import React from "react";
import { DocumentFormData, DocumentStatus } from "../document";
import { STATUS_LABELS } from "../document";
import FileUpload from "../FileUpload";

interface EditModalProps {
  isOpen: boolean;
  onClose: () => void;
  editingDocument: any | null;
  newDocument: DocumentFormData;
  setNewDocument: (doc: DocumentFormData) => void;
  formErrors: { title: boolean; source: boolean; assigned_to: boolean };
  setFormErrors: (errors: any) => void;
  tagsInput: string;
  setTagsInput: (input: string) => void;
  onAddTag: () => void;
  onRemoveTag: (tag: string) => void;
  onSubmit: (e: React.FormEvent) => void;
  documentTypes: string[];
  documentStatuses: DocumentStatus[];
  assignees: string[];
  getWorkflowStep: (status: DocumentStatus) => 1 | 2 | 3 | 4 | 5;
  getWorkflowProgress: (status: DocumentStatus) => number;
}

const EditModal: React.FC<EditModalProps> = ({
  isOpen,
  onClose,
  editingDocument,
  newDocument,
  setNewDocument,
  formErrors,
  setFormErrors,
  tagsInput,
  setTagsInput,
  onAddTag,
  onRemoveTag,
  onSubmit,
  documentTypes,
  documentStatuses,
  assignees,
  getWorkflowStep,
  getWorkflowProgress,
}) => {
  if (!isOpen) return null;

  return (
    <>
      <div className="fixed inset-0 bg-black bg-opacity-50 z-50 animate-fade-in" onClick={onClose}></div>
      <div className="fixed inset-0 z-50 flex items-center justify-center p-4 animate-scale-in">
        <div className="bg-white dark:bg-gray-800 rounded-xl shadow-2xl max-w-2xl w-full max-h-[90vh] overflow-y-auto animate-slide-up" onClick={(e) => e.stopPropagation()}>
          <div className="px-6 py-4 border-b border-gray-200 dark:border-gray-700 flex justify-between items-center">
            <h3 className="text-xl font-bold">
              <i className={`fas ${editingDocument ? 'fa-edit' : 'fa-file-plus'} mr-2 text-primary`}></i>
              {editingDocument ? `Modifier : ${editingDocument.title}` : 'Nouveau document'}
            </h3>
            <button onClick={onClose} className="text-gray-400 hover:text-gray-600 transition-colors">
              <i className="fas fa-times text-xl"></i>
            </button>
          </div>
          <form onSubmit={onSubmit} className="p-6">
            {/* Titre */}
            <div className="mb-5">
              <label htmlFor="doc-title" className="block text-sm font-medium mb-2">
                Titre du document <span className="text-red-500">*</span>
              </label>
              <input
                id="doc-title"
                type="text"
                value={newDocument.title}
                onChange={(e) => {
                  setNewDocument({ ...newDocument, title: e.target.value });
                  if (formErrors.title) setFormErrors({ ...formErrors, title: false });
                }}
                className={`w-full px-4 py-2.5 border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary transition-all duration-200 ${
                  formErrors.title ? 'border-red-500' : 'border-gray-300 dark:border-gray-600'
                } dark:bg-gray-700 dark:text-white`}
                required
              />
              {formErrors.title && <p className="mt-1 text-xs text-red-500 animate-fade-in">Le titre est requis</p>}
            </div>

            {/* Type et Source */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-5 mb-5">
              <div>
                <label htmlFor="doc-type" className="block text-sm font-medium mb-2">Type de document</label>
                <select
                  id="doc-type"
                  value={newDocument.type}
                  onChange={(e) => setNewDocument({ ...newDocument, type: e.target.value as any })}
                  className="w-full px-4 py-2.5 border border-gray-300 dark:border-gray-600 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary dark:bg-gray-700 dark:text-white transition-all duration-200"
                >
                  {documentTypes.map((type) => (
                    <option key={type} value={type}>
                      {type}
                    </option>
                  ))}
                </select>
              </div>
              <div>
                <label htmlFor="doc-source" className="block text-sm font-medium mb-2">
                  Source <span className="text-red-500">*</span>
                </label>
                <input
                  id="doc-source"
                  type="text"
                  value={newDocument.source}
                  onChange={(e) => {
                    setNewDocument({ ...newDocument, source: e.target.value });
                    if (formErrors.source) setFormErrors({ ...formErrors, source: false });
                  }}
                  className={`w-full px-4 py-2.5 border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary transition-all duration-200 ${
                    formErrors.source ? 'border-red-500' : 'border-gray-300 dark:border-gray-600'
                  } dark:bg-gray-700 dark:text-white`}
                  required
                />
                {formErrors.source && <p className="mt-1 text-xs text-red-500 animate-fade-in">La source est requise</p>}
              </div>
            </div>

            {/* Statut et Progression */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-5 mb-5">
              <div>
                <label htmlFor="doc-status" className="block text-sm font-medium mb-2">Statut éditorial</label>
                <select
                  id="doc-status"
                  value={newDocument.status}
                  onChange={(e) => {
                    const value = e.target.value as DocumentStatus;
                    setNewDocument({
                      ...newDocument,
                      status: value,
                      workflow_step: getWorkflowStep(value),
                      progress: getWorkflowProgress(value),
                    });
                  }}
                  className="w-full px-4 py-2.5 border border-gray-300 dark:border-gray-600 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary dark:bg-gray-700 dark:text-white transition-all duration-200"
                >
                  {documentStatuses.map((status) => (
                    <option key={status} value={status}>
                      {STATUS_LABELS[status]}
                    </option>
                  ))}
                </select>
              </div>
              <div>
                <label htmlFor="doc-progress" className="block text-sm font-medium mb-2">Progression (%)</label>
                <input
                  id="doc-progress"
                  type="number"
                  min="0"
                  max="100"
                  value={newDocument.progress}
                  onChange={(e) => {
                    const v = parseInt(e.target.value) || 0;
                    setNewDocument({ ...newDocument, progress: Math.min(100, Math.max(0, v)) });
                  }}
                  className="w-full px-4 py-2.5 border border-gray-300 dark:border-gray-600 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary dark:bg-gray-700 dark:text-white transition-all duration-200"
                />
              </div>
            </div>

            {/* Assignation */}
            <div className="mb-5">
              <label htmlFor="doc-assigned" className="block text-sm font-medium mb-2">
                Assigné à <span className="text-red-500">*</span>
              </label>
              <select
                id="doc-assigned"
                value={newDocument.assigned_to}
                onChange={(e) => {
                  setNewDocument({ ...newDocument, assigned_to: e.target.value });
                  if (formErrors.assigned_to) setFormErrors({ ...formErrors, assigned_to: false });
                }}
                className={`w-full px-4 py-2.5 border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary transition-all duration-200 ${
                  formErrors.assigned_to ? 'border-red-500' : 'border-gray-300 dark:border-gray-600'
                } dark:bg-gray-700 dark:text-white`}
                required
              >
                <option value="">-- Sélectionner --</option>
                {assignees.map((assignee) => (
                  <option key={assignee} value={assignee}>
                    {assignee}
                  </option>
                ))}
              </select>
              {formErrors.assigned_to && <p className="mt-1 text-xs text-red-500 animate-fade-in">Veuillez sélectionner</p>}
            </div>

            {/* Gestion des tags */}
            <div className="mb-6">
              <label className="block text-sm font-medium mb-2">
                Tags <span className="text-xs text-gray-500">(Entrée ou +)</span>
              </label>
              <div className="flex gap-2 mb-2">
                <input
                  type="text"
                  value={tagsInput}
                  onChange={(e) => setTagsInput(e.target.value)}
                  onKeyPress={(e) => e.key === 'Enter' && (e.preventDefault(), onAddTag())}
                  className="flex-1 px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary dark:bg-gray-700 dark:text-white transition-all duration-200"
                  placeholder="Ex: Volume 1, Yaoundé..."
                />
                <button type="button" onClick={onAddTag} className="px-4 py-2 bg-primary hover:bg-primary-dark text-white rounded-lg transition-all duration-200 hover:shadow-lg">
                  +
                </button>
              </div>
              <div className="flex flex-wrap gap-2">
                {(newDocument.tags || []).map((tag, index) => (
                  <span key={index} className="px-3 py-1.5 bg-blue-100 dark:bg-blue-900/30 text-blue-800 dark:text-blue-200 rounded-full flex items-center gap-1 animate-scale-in">
                    #{tag}
                    <button type="button" onClick={() => onRemoveTag(tag)} className="hover:text-blue-600 transition-colors">
                      <i className="fas fa-times text-xs"></i>
                    </button>
                  </span>
                ))}
              </div>
            </div>

            {/* Gestion des fichiers joints */}
            <div className="mb-6 pt-4 border-t border-gray-200 dark:border-gray-700">
              <h4 className="text-sm font-medium text-gray-700 dark:text-gray-300 mb-3 flex items-center">
                <i className="fas fa-paperclip mr-2 text-gray-500"></i>
                Fichier attaché
              </h4>
              <FileUpload
                documentId={editingDocument?.id || 'new'}
                currentFileUrl={newDocument.file_url || null}
                onFileUploaded={(url) => {
                  setNewDocument({ ...newDocument, file_url: url });
                }}
                onFileDeleted={() => {
                  setNewDocument({ ...newDocument, file_url: '' });
                }}
                maxFileSize={50 * 1024 * 1024}
              />
              {newDocument.file_url && (
                <p className="mt-2 text-xs text-green-600 dark:text-green-400 flex items-center animate-fade-in">
                  <i className="fas fa-check-circle mr-1.5"></i>
                  Fichier attaché : {decodeURIComponent(newDocument.file_url.split('/').pop() || '')}
                </p>
              )}
            </div>

            {/* Actions */}
            <div className="flex flex-col sm:flex-row sm:justify-end gap-3 pt-4 border-t border-gray-200 dark:border-gray-700">
              <button type="button" onClick={onClose} className="px-5 py-2.5 text-sm font-medium bg-gray-100 dark:bg-gray-700 hover:bg-gray-200 dark:hover:bg-gray-600 rounded-lg transition-all duration-200">
                Annuler
              </button>
              <button type="submit" className="px-5 py-2.5 text-sm font-medium text-white bg-primary hover:bg-primary-dark rounded-lg flex items-center transition-all duration-200 hover:shadow-lg">
                <i className={`fas ${editingDocument ? 'fa-save' : 'fa-plus'} mr-2`}></i>
                {editingDocument ? 'Mettre à jour' : 'Créer le document'}
              </button>
            </div>
          </form>
        </div>
      </div>
    </>
  );
};

export default EditModal;